const amqp = require('amqplib');

async function startConsumer() {
  try {
    const connection = await amqp.connect('amqp://localhost');
    const channel = await connection.createChannel();

    const queueName = 'payment-events';

    // Assert the queue exists or create it
    await channel.assertQueue(queueName, { durable: true });

    console.log('Waiting for payment events...');

    // Consume messages from the queue
    channel.consume(queueName, async (msg) => {
      if (msg !== null) {
        const messageContent = msg.content.toString();
        console.log('Received payment event:', messageContent);

        // Execute payment logic based on message content
        try {
          await processPayment(messageContent);
          channel.ack(msg); // Acknowledge the message
        } catch (error) {
          console.error('Error processing payment:', error);
          channel.nack(msg, false, true); // Reject the message and requeue it
        }
      }
    });
  } catch (err) {
    console.error('Error starting consumer:', err);
  }
}

